const query = $('Review Queue API').first().json.query || {};
const allowed = ['draft', 'approved', 'approved_edited', 'rejected'];
const filterStatus = String(query.status || '').trim();
const rows = $input.all().map(item => item.json);
const filtered = rows
  .filter(row => allowed.includes(String(row.status || '')))
  .filter(row => !filterStatus || String(row.status || '') === filterStatus)
  .sort((a, b) => String(b.submitted_at || '').localeCompare(String(a.submitted_at || '')))
  .map(row => ({
    run_id: row.run_id || '',
    submitted_at: row.submitted_at || '',
    meeting_title: row.meeting_title || '',
    department: row.department || '',
    meeting_type: row.meeting_type || '',
    status: row.status || '',
    reviewer_name: row.reviewer_name || '',
    reviewer_notes: row.reviewer_notes || '',
    has_edited_markdown: Boolean(String(row.final_markdown_edited || '').trim()),
  }));
return [{ json: { ok: true, items: filtered } }];
